        public void btnExport_OnClick(object sender, EventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            if (this.rdodetail.Checked || this.rdosummary.Checked)
            {
                string value = this.hdnInnerHtml.Value;
                base.Response.Cache.SetExpires(DateTime.Now.AddSeconds(1));
                base.Response.Clear();
                base.Response.AppendHeader("content-disposition", "attachment;filename=Invoice_List.xls");
                base.Response.Charset = "";
                base.Response.Cache.SetCacheability(HttpCacheability.NoCache);
                base.Response.ContentType = "application/vnd.ms-excel";
                this.EnableViewState = false;
                base.Response.Write("\r\n");
                base.Response.Write(value);
                base.Response.End();
                return;
            }
            int num = 0;
            for (int i = 0; i < this.chkColumns.Items.Count; i++)
            {
                if (this.chkColumns.Items[i].Selected)
                {
                    num = 1;
                }
            }
            if (num != 1)
            {
                this.spnError.Visible = true;
                return;
            }
            DataSet estimateData = this.GetEstimateData(0);
            StringWriter stringWriter = new StringWriter();
            HtmlTextWriter htmlTextWriter = new HtmlTextWriter(stringWriter);
            GridView gridView = new GridView()
            {
                DataSource = estimateData,
                Width = Unit.Percentage(100),
                BorderWidth = 0,
                GridLines = GridLines.Both
            };
            gridView.HeaderStyle.Font.Bold = true;
            gridView.HeaderStyle.HorizontalAlign = HorizontalAlign.Left;
            gridView.CellPadding = 3;
            gridView.RowDataBound += new GridViewRowEventHandler(this.GridEstReport_RowDataBound);
            gridView.DataBind();
            for (int j = 0; j < gridView.Rows.Count; j++)
            {
                string text = gridView.Rows[j].Cells[0].Text;
                for (int k = j + 1; k < gridView.Rows.Count; k++)
                {
                    if (string.Compare(text, gridView.Rows[k].Cells[0].Text, true) == 0)
                    {
                        for (int l = 0; l < gridView.Rows[k].Cells.Count; l++)
                        {
                            if (string.Compare(gridView.Rows[j].Cells[l].Text, gridView.Rows[k].Cells[l].Text, true) == 0)
                            {
                                gridView.Rows[k].Cells[l].Text = string.Empty;
                            }
                        }
                    }
                }
            }
            gridView.RenderControl(htmlTextWriter);
            string str = string.Concat(this.CompanyName.Replace(" ", "_"), "_Invoice_List.xls");
            base.Response.ContentType = "application/vnd.ms-excel";
            base.Response.AppendHeader("content-disposition", string.Concat("attachment; filename=\"", str, "\""));
            this.EnableViewState = false;
            base.Response.Write(stringWriter.ToString());
            base.Response.End();
        }

