        protected void Page_Load(object sender, EventArgs e)
        {
            string[] languageConversion;
            BaseClass baseClass = new BaseClass();
            baseClass.ReturnRoles_Privileges_Reports("invoices", "showreport", "");
            BaseClass baseClass1 = new BaseClass();
            string empty = string.Empty;
            if (baseClass1.ReturnRoles_Privileges_ForGrid("invoices", "isdisplay", this.Page.Request.Url.ToString()).Trim().ToLower() == "false")
            {
                base.Response.Redirect(string.Concat(this.strSitepath, "accessdenied.aspx"));
            }
            this.rdosummary.Text = this.objLanguage.GetLanguageConversion("Summary");
            this.rdodetail.Text = this.objLanguage.GetLanguageConversion("Detailed");
            this.chkEstimate.Text = this.objLanguage.GetLanguageConversion("Show_Invoices_With_No_Assigned_Value");
            this.chkDateOption.Text = this.objLanguage.GetLanguageConversion("Date_Options");
            this.btnCancel.Text = this.objLanguage.GetLanguageConversion("Cancel");
            this.btnSaveRun.Text = this.objLanguage.GetLanguageConversion("Save_And_Run");
            this.btnRunReport.Text = this.objLanguage.GetLanguageConversion("Run_Report");
            this.btnfilter.ToolTip = this.objLanguage.GetLanguageConversion("Back_To_Search_Option");
            this.btnExport1.ToolTip = this.objLanguage.GetLanguageConversion("Export_Presentation_Format");
            this.btnNewExport.ToolTip = this.objLanguage.GetLanguageConversion("Export_Excel_Format");
            this.chkColumns.Items[62].Text = this.objLanguage.GetLanguageConversion("Quantity");
            if (baseClass1.ReturnRoles_Privileges_ReportStatus("invoices", "exportreport").Trim().ToLower() != "false")
            {
                this.btnExport1.Visible = true;
                this.btnNewExport.Visible = true;
            }
            else
            {
                this.btnExport1.Visible = false;
                this.btnNewExport.Visible = false;
            }
            if (this.rdosummary.Checked)
            {
                System.Web.UI.ScriptManager.RegisterStartupScript(this, base.GetType(), " ", "javascript:GetSummaryDetails();", true);
            }
            else if (this.rdodetail.Checked)
            {
                System.Web.UI.ScriptManager.RegisterStartupScript(this, base.GetType(), " ", "javascript:GetDetails();", true);
            }
            this.pg = "invoice";
            if (base.Request.Params["pg"] == null)
            {
                this.pagename = "invoice";
            }
            else if (base.Request.Params["pg"].ToString().Trim().ToLower() == "report")
            {
                this.pagename = "Report";
            }
            global.pageName = this.pagename;
            global.pgName = "";
            this.gloobj.setpagename(this.pagename);
            base.Title = this.objLanguage.convert(global.pageTitle("Invoice Report", int.Parse(this.Session["companyid"].ToString()), this.Session["companyName"].ToString()));
            if (this.pagename.ToString().ToLower().Trim() != "report")
            {
                languageConversion = new string[] { "<a href=../welcome.aspx class='subnavigator'  style='text-decoration:underline;'>", this.objLanguage.GetLanguageConversion("Home_Page_Details"), "</a>&nbsp;>&nbsp;<a href=../invoice/invoice_view.aspx class='subnavigator'  style='text-decoration:underline;'>", this.objLanguage.GetLanguageConversion("Invoice_View"), "</a>" };
                base.Navigation_Path(string.Concat(languageConversion), string.Concat("&nbsp;>&nbsp;", this.objLanguage.GetLanguageConversion("Invoice_Report")));
            }
            else
            {
                base.Navigation_Path(string.Concat("<a href=../welcome.aspx class='subnavigator' style=text-decoration:underline>", this.objLanguage.GetLanguageConversion("Home_Page_Details"), "</a>"), string.Concat("&nbsp;>&nbsp;<a href=../common/report.aspx class='subnavigator' style=text-decoration:underline>", this.objLanguage.GetLanguageConversion("Reports"), "</a>&nbsp;>&nbsp;", this.objLanguage.GetLanguageConversion("Invoice_Report")));
            }
            this.CompanyID = Convert.ToInt32(this.Session["companyid"].ToString());
            this.UserID = Convert.ToInt32(this.Session["UserID"].ToString());
            if (!base.IsPostBack)
            {
                this.chkColumns.Items[16].Selected = true;
                this.chkColumns.Items[17].Selected = true;
                this.Check_SpecialPrivilege = false;
                this.Check_SpecialPrivilege = base.Check_SpecialPrivilege_For_User((long)this.UserID, (long)this.CompanyID);
                if (this.Session["CustomAccessRight"].ToString().Trim().ToLower() != "false")
                {
                    string str = string.Empty;
                    if (baseClass.ReturnRoles_Privileges_Others("showsubtotal").ToLower() != "false")
                    {
                        this.chkColumns.Items[39].Enabled = true;
                        this.chkExcTax.Items[1].Selected = true;
                        this.chkExcTax.Items[1].Enabled = true;
                    }
                    else
